+#[test]
+fn nss_systemd_get_by_int_stubs_return_notfound_and_set_errno() {
+    use frankenlibc_abi::unistd_abi::{_nss_systemd_getgrgid_r, _nss_systemd_getpwuid_r};
+    let mut err = 0;
+    assert_eq!(
+        unsafe {
